#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* segregateOddEven(ListNode* head) {
        if (!head) return nullptr;
        ListNode odd_dummy(0), even_dummy(0);
        ListNode *odd_tail = &odd_dummy, *even_tail = &even_dummy;
        while (head) {
            ListNode* nxt = head->next;
            head->next = nullptr;
            if (head->val % 2 == 1) {
                odd_tail->next = head;
                odd_tail = odd_tail->next;
            } else {
                even_tail->next = head;
                even_tail = even_tail->next;
            }
            head = nxt;
        }
        odd_tail->next = even_dummy.next;
        return odd_dummy.next;
    }
};

ListNode* buildList(const vector<int>& vals) {
    ListNode dummy(0);
    ListNode* cur = &dummy;
    for (int v : vals) {
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    return dummy.next;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    ListNode* head = buildList(vals);
    Solution sol;
    ListNode* new_head = sol.segregateOddEven(head);
    bool first = true;
    for (ListNode* cur = new_head; cur; cur = cur->next) {
        if (!first) cout << ' ';
        first = false;
        cout << cur->val;
    }
    cout << "\n";
    return 0;
}
